import{_ as e,c as a,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"バージョンログ: 機能アップデート | OpenSkills","description":"OpenSkillsのバージョン変更履歴を確認し、updateコマンド、シンボリックリンク、プライベートリポジトリなどの新機能、およびパストラバーサル保護などの重要な改善と問題修正を確認しましょう。","frontmatter":{"title":"バージョンログ: 機能アップデート | OpenSkills","sidebarTitle":"新機能を見る","subtitle":"バージョンログ: 機能アップデート | OpenSkills","description":"OpenSkillsのバージョン変更履歴を確認し、updateコマンド、シンボリックリンク、プライベートリポジトリなどの新機能、およびパストラバーサル保護などの重要な改善と問題修正を確認しましょう。","tags":["changelog","version history"],"order":1},"headers":[],"relativePath":"ja/numman-ali/openskills/changelog/changelog/index.md","filePath":"ja/numman-ali/openskills/changelog/changelog/index.md"}'),r={name:"ja/numman-ali/openskills/changelog/changelog/index.md"};function t(n,l,s,d,h,c){return i(),a("div",null,[...l[0]||(l[0]=[o('<h1 id="更新履歴" tabindex="-1">更新履歴 <a class="header-anchor" href="#更新履歴" aria-label="Permalink to &quot;更新履歴&quot;">​</a></h1><p>本ページでは、OpenSkillsのバージョン変更履歴を記録し、各バージョンの新機能、改善、および問題修正について理解できるようにします。</p><hr><h2 id="_1-5-0-2026-01-17" tabindex="-1">[1.5.0] - 2026-01-17 <a class="header-anchor" href="#_1-5-0-2026-01-17" aria-label="Permalink to &quot;[1.5.0] - 2026-01-17&quot;">​</a></h2><h3 id="新機能" tabindex="-1">新機能 <a class="header-anchor" href="#新機能" aria-label="Permalink to &quot;新機能&quot;">​</a></h3><ul><li><strong><code>openskills update</code></strong> - 記録されたソースからインストール済みスキルを更新（デフォルト：すべて更新）</li><li><strong>ソースメタデータ追跡</strong> - インストール時にソース情報を記録し、スキルの確実な更新に使用</li></ul><h3 id="改善" tabindex="-1">改善 <a class="header-anchor" href="#改善" aria-label="Permalink to &quot;改善&quot;">​</a></h3><ul><li><strong>複数スキル読み取り</strong> - <code>openskills read</code>コマンドが、コンマ区切りのスキル名リストをサポート</li><li><strong>生成される使用説明の最適化</strong> - シェル環境でのreadコマンド呼び出しヒントを最適化</li><li><strong>README</strong> - 更新ガイドと手動使用のヒントを追加</li></ul><h3 id="問題修正" tabindex="-1">問題修正 <a class="header-anchor" href="#問題修正" aria-label="Permalink to &quot;問題修正&quot;">​</a></h3><ul><li><strong>更新体験の最適化</strong> - ソースメタデータのないスキルをスキップし、これらのスキルをリストして再インストールを促す</li></ul><hr><h2 id="_1-4-0-2026-01-17" tabindex="-1">[1.4.0] - 2026-01-17 <a class="header-anchor" href="#_1-4-0-2026-01-17" aria-label="Permalink to &quot;[1.4.0] - 2026-01-17&quot;">​</a></h2><h3 id="改善-1" tabindex="-1">改善 <a class="header-anchor" href="#改善-1" aria-label="Permalink to &quot;改善&quot;">​</a></h3><ul><li><strong>README</strong> - プロジェクトローカルのデフォルトインストール方法を明確化し、冗長なsyncヒントを削除</li><li><strong>インストールメッセージ</strong> - インストーラーがプロジェクトローカルのデフォルトインストールと<code>--global</code>オプションを明確に区別</li></ul><hr><h2 id="_1-3-2-2026-01-17" tabindex="-1">[1.3.2] - 2026-01-17 <a class="header-anchor" href="#_1-3-2-2026-01-17" aria-label="Permalink to &quot;[1.3.2] - 2026-01-17&quot;">​</a></h2><h3 id="改善-2" tabindex="-1">改善 <a class="header-anchor" href="#改善-2" aria-label="Permalink to &quot;改善&quot;">​</a></h3><ul><li><strong>ドキュメントとAGENTS.mdガイド</strong> - すべてのコマンド例と生成される使用説明が<code>npx openskills</code>を統一的に使用</li></ul><hr><h2 id="_1-3-1-2026-01-17" tabindex="-1">[1.3.1] - 2026-01-17 <a class="header-anchor" href="#_1-3-1-2026-01-17" aria-label="Permalink to &quot;[1.3.1] - 2026-01-17&quot;">​</a></h2><h3 id="問題修正-1" tabindex="-1">問題修正 <a class="header-anchor" href="#問題修正-1" aria-label="Permalink to &quot;問題修正&quot;">​</a></h3><ul><li><strong>Windowsインストール</strong> - Windowsシステムのパス検証問題を修正（&quot;Security error: Installation path outside target directory&quot;）</li><li><strong>CLIバージョン</strong> - <code>npx openskills --version</code>がpackage.jsonからバージョン番号を正しく読み取るよう修正</li><li><strong>ルートディレクトリのSKILL.md</strong> - ルートディレクトリのSKILL.mdを持つ単一スキルリポジトリのインストール問題を修正</li></ul><hr><h2 id="_1-3-0-2025-12-14" tabindex="-1">[1.3.0] - 2025-12-14 <a class="header-anchor" href="#_1-3-0-2025-12-14" aria-label="Permalink to &quot;[1.3.0] - 2025-12-14&quot;">​</a></h2><h3 id="新機能-1" tabindex="-1">新機能 <a class="header-anchor" href="#新機能-1" aria-label="Permalink to &quot;新機能&quot;">​</a></h3><ul><li><p><strong>シンボリックリンクサポート</strong> - スキルをシンボリックリンク経由でスキルディレクトリにインストール可能 (<a href="https://github.com/numman-ali/openskills/issues/3" target="_blank" rel="noreferrer">#3</a>)</p><ul><li>クローン済みリポジトリからシンボリックリンクを作成してgitベースのスキル更新を実現</li><li>ローカルスキル開発ワークフローをサポート</li><li>壊れたシンボリックリンクは適切にスキップされる</li></ul></li><li><p><strong>設定可能な出力パス</strong> - syncコマンドに<code>--output</code> / <code>-o</code>オプションを追加 (<a href="https://github.com/numman-ali/openskills/issues/5" target="_blank" rel="noreferrer">#5</a>)</p><ul><li>任意の<code>.md</code>ファイルに同期可能（例：<code>.ruler/AGENTS.md</code>）</li><li>ファイルが存在しない場合は自動的にファイルを作成しタイトルを追加</li><li>必要に応じてネストされたディレクトリを自動的に作成</li></ul></li><li><p><strong>ローカルパスインストール</strong> - ローカルディレクトリからスキルをインストール可能 (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>絶対パス（<code>/path/to/skill</code>）をサポート</li><li>相対パス（<code>./skill</code>、<code>../skill</code>）をサポート</li><li>チルダ展開（<code>~/my-skills/skill</code>）をサポート</li></ul></li><li><p><strong>プライベートgitリポジトリサポート</strong> - プライベートリポジトリからスキルをインストール可能 (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>SSH URL（<code>git@github.com:org/private-skills.git</code>）</li><li>認証付きHTTPS URL</li><li>システムSSHキーを自動使用</li></ul></li><li><p><strong>包括的なテストスイート</strong> - 6つのテストファイルで88個のテスト</p><ul><li>シンボリックリンク検出、YAML解析のユニットテスト</li><li>install、syncコマンドの統合テスト</li><li>完全なCLIワークフローのエンドツーエンドテスト</li></ul></li></ul><h3 id="改善-3" tabindex="-1">改善 <a class="header-anchor" href="#改善-3" aria-label="Permalink to &quot;改善&quot;">​</a></h3><ul><li><p><strong><code>--yes</code>フラグがすべてのプロンプトをスキップ</strong> - 完全非対話モードでCI/CDに最適 (<a href="https://github.com/numman-ali/openskills/issues/6" target="_blank" rel="noreferrer">#6</a>)</p><ul><li>既存スキル上書き時のプロンプトをスキップ</li><li>プロンプトスキップ時に<code>Overwriting: &lt;skill-name&gt;</code>メッセージを表示</li><li>すべてのコマンドがヘッドレス環境で実行可能</li></ul></li><li><p><strong>CIワークフローの再配置</strong> - ビルドステップがテストの前に実行されるよう変更</p><ul><li>エンドツーエンドテスト用に<code>dist/cli.js</code>が存在することを保証</li></ul></li></ul><h3 id="セキュリティ" tabindex="-1">セキュリティ <a class="header-anchor" href="#セキュリティ" aria-label="Permalink to &quot;セキュリティ&quot;">​</a></h3><ul><li><strong>パストラバーサル保護</strong> - インストールパスがターゲットディレクトリ内に収まることを検証</li><li><strong>シンボリックリンクの参照解除</strong> - <code>cpSync</code>は<code>dereference: true</code>を使用してシンボリックリンクターゲットを安全にコピー</li><li><strong>非貪欲なYAML正規表現</strong> - frontmatter解析で潜在的なReDoS攻撃を防止</li></ul><hr><h2 id="_1-2-1-2025-10-27" tabindex="-1">[1.2.1] - 2025-10-27 <a class="header-anchor" href="#_1-2-1-2025-10-27" aria-label="Permalink to &quot;[1.2.1] - 2025-10-27&quot;">​</a></h2><h3 id="問題修正-2" tabindex="-1">問題修正 <a class="header-anchor" href="#問題修正-2" aria-label="Permalink to &quot;問題修正&quot;">​</a></h3><ul><li>READMEドキュメントのクリーンアップ - 重複部分と間違ったフラグを削除</li></ul><hr><h2 id="_1-2-0-2025-10-27" tabindex="-1">[1.2.0] - 2025-10-27 <a class="header-anchor" href="#_1-2-0-2025-10-27" aria-label="Permalink to &quot;[1.2.0] - 2025-10-27&quot;">​</a></h2><h3 id="新機能-2" tabindex="-1">新機能 <a class="header-anchor" href="#新機能-2" aria-label="Permalink to &quot;新機能&quot;">​</a></h3><ul><li><code>--universal</code>フラグでスキルを<code>.claude/skills/</code>ではなく<code>.agent/skills/</code>にインストール <ul><li>マルチエージェント環境に対応（Claude Code + Cursor/Windsurf/Aider）</li><li>Claude Codeのネイティブマーケットプラグインとの競合を回避</li></ul></li></ul><h3 id="改善-4" tabindex="-1">改善 <a class="header-anchor" href="#改善-4" aria-label="Permalink to &quot;改善&quot;">​</a></h3><ul><li>プロジェクトローカルインストールがデフォルトになりました（以前はグローバルインストール）</li><li>スキルはデフォルトで<code>./.claude/skills/</code>にインストールされます</li></ul><hr><h2 id="_1-1-0-2025-10-27" tabindex="-1">[1.1.0] - 2025-10-27 <a class="header-anchor" href="#_1-1-0-2025-10-27" aria-label="Permalink to &quot;[1.1.0] - 2025-10-27&quot;">​</a></h2><h3 id="新機能-3" tabindex="-1">新機能 <a class="header-anchor" href="#新機能-3" aria-label="Permalink to &quot;新機能&quot;">​</a></h3><ul><li>技術的な深い洞察を含む包括的な単一ページREADME</li><li>Claude Codeとの並列比較</li></ul><h3 id="問題修正-3" tabindex="-1">問題修正 <a class="header-anchor" href="#問題修正-3" aria-label="Permalink to &quot;問題修正&quot;">​</a></h3><ul><li>インストール位置に応じてロケーションプロンプトが正しく<code>project</code>または<code>global</code>を表示するよう修正</li></ul><hr><h2 id="_1-0-0-2025-10-26" tabindex="-1">[1.0.0] - 2025-10-26 <a class="header-anchor" href="#_1-0-0-2025-10-26" aria-label="Permalink to &quot;[1.0.0] - 2025-10-26&quot;">​</a></h2><h3 id="新機能-4" tabindex="-1">新機能 <a class="header-anchor" href="#新機能-4" aria-label="Permalink to &quot;新機能&quot;">​</a></h3><ul><li>初期リリース</li><li><code>npx openskills install &lt;source&gt;</code> - GitHubリポジトリからスキルをインストール</li><li><code>npx openskills sync</code> - AGENTS.md用の<code>&lt;available_skills&gt;</code> XMLを生成</li><li><code>npx openskills list</code> - インストール済みスキルを表示</li><li><code>npx openskills read &lt;name&gt;</code> - エージェント用にスキルコンテンツを読み込み</li><li><code>npx openskills manage</code> - 対話的なスキル削除</li><li><code>npx openskills remove &lt;name&gt;</code> - 指定したスキルを削除</li><li>すべてのコマンドの対話的なTUIインターフェース</li><li>AnthropicのSKILL.md形式に対応</li><li>プログレッシブディスクロージャ（スキルのオンデマンド読み込み）</li><li>バンドルリソースに対応（references/、scripts/、assets/）</li></ul><hr><h2 id="付録-ソースコードリファレンス" tabindex="-1">付録：ソースコードリファレンス <a class="header-anchor" href="#付録-ソースコードリファレンス" aria-label="Permalink to &quot;付録：ソースコードリファレンス&quot;">​</a></h2><details><summary><strong>クリックしてソースコード位置を確認</strong></summary><blockquote><p>更新日時：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th></tr></thead><tbody><tr><td>更新ログ原文</td><td><a href="https://github.com/numman-ali/openskills/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td></tr></tbody></table></details>',53)])])}const m=e(r,[["render",t]]);export{g as __pageData,m as default};
